const maxContacts = Number($env.CAMPAIGN_MAX_CONTACTS || 200);
const groupFilterRaw = String($env.CAMPAIGN_GROUP_FILTER || '').trim();
const ownerFilterRaw = String($env.CAMPAIGN_OWNER_FILTER || '').trim();
const targetNameRaw = String($env.CAMPAIGN_TARGET_NAME || '').trim();
const targetGroupRaw = String($env.CAMPAIGN_TARGET_GROUP || '').trim();
const validationMode = String($env.CAMPAIGN_VALIDATION_MODE || 'name_group').trim().toLowerCase();
const audienceModeRaw = String($env.CAMPAIGN_AUDIENCE || 'clientes').trim().toLowerCase();
const audienceMode = ['clientes', 'parceiros', 'todos'].includes(audienceModeRaw) ? audienceModeRaw : 'clientes';
const skipAdmins = String($env.CAMPAIGN_SKIP_ADMINS || 'true').toLowerCase() === 'true';
const allowNonBr = String($env.CAMPAIGN_ALLOW_NON_BR || 'false').toLowerCase() === 'true';
const ticketDefault = String($env.CAMPAIGN_TICKET_DEFAULT || 'premium').trim().toLowerCase();
const ownerHintsRhuanRaw = String($env.CAMPAIGN_OWNER_HINTS_RHUAN || '').trim();
const ownerHintsHugoRaw = String($env.CAMPAIGN_OWNER_HINTS_HUGO || '').trim();

const seen = new Set();
const namedContacts = [];
const unnamedContacts = [];

const normalizeText = (value) => String(value || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase();

const parseList = (value) => String(value || '')
  .split(/[;,|]/)
  .map((item) => normalizeText(item).trim())
  .filter(Boolean);

const isTruthy = (value) => {
  const v = normalizeText(value).trim();
  return ['1', 'true', 'sim', 'yes', 'y'].includes(v);
};

const groupFilters = parseList(groupFilterRaw);
const ownerFilters = parseList(ownerFilterRaw);
const ownerHintsRhuan = parseList(ownerHintsRhuanRaw);
const ownerHintsHugo = parseList(ownerHintsHugoRaw);
const targetNameNorm = normalizeText(targetNameRaw);
const targetGroupNorm = normalizeText(targetGroupRaw);
const directTargetEnabled = !!targetNameNorm || !!targetGroupNorm;

const isValidBrLocal = (digits) => {
  if (!(digits.length === 10 || digits.length === 11)) return false;

  const ddd = digits.slice(0, 2);
  if (!/^[1-9][0-9]$/.test(ddd)) return false;

  if (digits.length === 11) {
    return digits[2] === '9';
  }

  return /^[2-5]/.test(digits[2]);
};

const normalizePhone = (value) => {
  const digits = String(value || '').replace(/\D/g, '');
  if (!digits) return '';

  if (allowNonBr) {
    return (digits.length >= 10 && digits.length <= 15) ? digits : '';
  }

  if (digits.startsWith('55')) {
    const local = digits.slice(2);
    return isValidBrLocal(local) ? digits : '';
  }

  return isValidBrLocal(digits) ? `55${digits}` : '';
};
const cleanName = (value) => String(value || '')
  .replace(/\s+/g, ' ')
  .replace(/[^\p{L}\p{N}\s'.-]/gu, '')
  .trim();

const cleanTag = (value) => String(value || '')
  .trim()
  .replace(/^@+/, '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^\p{L}\p{N}_.]/gu, '')
  .toLowerCase();

const chooseName = (row) => {
  const candidates = [
    row.nome,
    row.name,
    row.first_name,
    row.nome_contato,
    row.contato,
    row.contact_name,
  ];

  for (const candidate of candidates) {
    const clean = cleanName(candidate);
    if (!clean) continue;
    const lower = clean.toLowerCase();
    if (['cliente', 'contato', 'na', 'n/a', 'unknown'].includes(lower)) continue;
    return clean;
  }

  return '';
};

const chooseMentionTag = (row, nome, phone) => {
  const candidates = [
    row.arroba,
    row.handle,
    row.username,
    row.user,
    row.instagram,
    row.contato_tag,
    row.tag,
    row.mention,
  ];

  for (const candidate of candidates) {
    const clean = cleanTag(candidate);
    if (clean) return `@${clean}`;
  }

  const firstNameTag = cleanTag(nome ? nome.split(' ')[0] : '');
  if (firstNameTag) return `@${firstNameTag}`;

  return phone ? `@${phone}` : '@cliente';
};

const inferOwner = (row, groupPrincipal, groupsOrigem, origemArquivo) => {
  const explicitOwner = String(row.origem_responsavel || row.owner || row.responsavel_origem || '').trim();
  if (explicitOwner) return explicitOwner;

  const source = normalizeText([
    row.nome || '',
    groupPrincipal || '',
    groupsOrigem || '',
    origemArquivo || '',
  ].join(' | '));

  if (source.includes('rhuan')) return 'Rhuan';
  if (source.includes('hugo')) return 'Hugo';

  if (ownerHintsRhuan.some((term) => source.includes(term))) return 'Rhuan';
  if (ownerHintsHugo.some((term) => source.includes(term))) return 'Hugo';

  return 'Equipe Hogar';
};

const extractTicketValue = (rawText) => {
  const text = String(rawText || '').trim();
  if (!text) return 0;

  const matches = text.match(/\d[\d.,]*/g) || [];
  let maxValue = 0;

  for (const token of matches) {
    const cleaned = token.replace(/\./g, '').replace(/,/g, '.');
    const value = Number(cleaned);
    if (Number.isFinite(value) && value > maxValue) {
      maxValue = value;
    }
  }

  return maxValue;
};

const inferTicketSegment = (ticketValue) => {
  if (ticketValue >= 2500000) return 'premium_plus';
  if (ticketValue >= 1500000) return 'premium';
  if (ticketValue >= 700000) return 'medio';
  if (ticketValue > 0) return 'entrada';
  return ticketDefault;
};

const inferGroupProfile = (groupPrincipal, categoria) => {
  const g = normalizeText(groupPrincipal);
  const c = normalizeText(categoria);

  if (/corretor|imobiliaria|broker|parceir/.test(g) || /corretor|parceiro/.test(c)) return 'parceiro';
  if (/invest|capital|renda/.test(g) || /invest/.test(c)) return 'investidor';
  if (/condominio|morador|residencial|vizinhanca/.test(g)) return 'morador';
  if (/luxo|alto padrao|premium/.test(g)) return 'luxo';
  return 'geral';
};

const recommendOpportunity = (profile, ticketSegment, focus) => {
  const key = `${profile}:${ticketSegment}`;
  const map = {
    'parceiro:premium_plus': 'imoveis de luxo acima de R$ 2,5M com parceria estrategica',
    'parceiro:premium': 'imoveis de alto padrao com comissionamento competitivo',
    'parceiro:medio': 'imoveis com giro rapido para parceria comercial',

    'investidor:premium_plus': 'ativos imobiliarios premium para preservacao de patrimonio',
    'investidor:premium': 'imoveis de alto padrao com foco em valorizacao e renda',
    'investidor:medio': 'oportunidades imobiliarias com bom equilibrio risco-retorno',

    'morador:premium_plus': 'residencias de luxo exclusivas com alto nivel de acabamento',
    'morador:premium': 'imoveis premium em localizacoes nobres',
    'morador:medio': 'imoveis bem localizados com condicoes especiais',

    'luxo:premium_plus': 'oportunidades signature da carteira Hogar Imoveis de Luxo',
    'luxo:premium': 'imoveis de luxo com oferta diferenciada da semana',
    'luxo:medio': 'imoveis de alto padrao com excelente custo-beneficio',
  };

  return map[key] || focus || 'imoveis de luxo';
};

for (const item of $input.all()) {
  const row = item.json || {};
  const phone = normalizePhone(row.whatsapp || row.telefone || row.celular || row.phone || row.numero);
  if (!phone) continue;
  if (seen.has(phone)) continue;

  if (skipAdmins && isTruthy(row.eh_admin)) {
    continue;
  }

  const groupsRaw = String(row.grupos_origem || row.grupo_origem || '').trim();
  const groups = groupsRaw
    .replace(/excel results/ig, '')
    .replace(/\s*\|\s*/g, ' | ')
    .replace(/\s+/g, ' ')
    .trim();
  const groupMain = groups ? groups.split('|')[0].trim() : '';

  if (groupFilters.length) {
    const gNorm = normalizeText(groups);
    const isGroupFilterMatch = groupFilters.some((term) => gNorm.includes(term));
    if (!isGroupFilterMatch) continue;
  }

  const origemArquivo = String(row.arquivos_origem || row.origem_arquivo || '').trim();
  const owner = inferOwner(row, groupMain, groups, origemArquivo);

  if (ownerFilters.length) {
    const ownerNorm = normalizeText(owner);
    const isOwnerMatch = ownerFilters.some((term) => ownerNorm.includes(term));
    if (!isOwnerMatch) continue;
  }

  const nome = chooseName(row);
  const nameNorm = normalizeText(nome);
  const groupNorm = normalizeText(groupMain || groups);

  const matchName = !targetNameNorm || (nameNorm && nameNorm.includes(targetNameNorm));
  const matchGroup = !targetGroupNorm || (groupNorm && groupNorm.includes(targetGroupNorm));

  if (directTargetEnabled && (!matchName || !matchGroup)) {
    continue;
  }

  const categoriaRaw = String(row.categoria || row.tipo || 'Cliente').trim() || 'Cliente';
  const categoriaNorm = normalizeText(categoriaRaw);
  const groupAudienceNorm = normalizeText(groupMain || groups);
  const isPartnerAudienceContact = /corretor|parceiro|imobiliaria|broker/.test(categoriaNorm)
    || /corretor|parceir|imobiliaria|broker/.test(groupAudienceNorm);

  if (audienceMode === 'clientes' && isPartnerAudienceContact) {
    continue;
  }

  if (audienceMode === 'parceiros' && !isPartnerAudienceContact) {
    continue;
  }

  seen.add(phone);

  const primeiroNome = nome ? nome.split(' ')[0] : '';
  const categoria = categoriaRaw;
  const telefoneCsv = String(row.telefone || '').replace(/\D/g, '');
  const whatsappCsv = String(row.whatsapp || '').replace(/\D/g, '');
  const mentionTag = chooseMentionTag(row, nome, phone);
  const atNomeRaw = cleanTag(primeiroNome);

  const ticketRaw = String(
    row.ticket_interesse
      || row.ticket
      || row.investimento
      || row.orcamento
      || row.faixa_preco
      || row.ticket_faixa
      || row.faixa
      || row.budget
      || ''
  ).trim();
  const ticketValue = extractTicketValue(ticketRaw);
  const ticketSegment = inferTicketSegment(ticketValue);
  const profile = inferGroupProfile(groupMain, categoria);
  const focus = String($env.CAMPAIGN_TEMPLATE_FOCUS || 'imoveis de luxo').trim();
  const opportunity = recommendOpportunity(profile, ticketSegment, focus);

  const ownerPhrase = /rhuan|hugo/i.test(owner) ? owner : 'nossa equipe';
  const origemMensagem = groupMain
    ? `Peguei seu contato no grupo "${groupMain}" com ${ownerPhrase}.`
    : `Peguei seu contato por indicacao com ${ownerPhrase}.`;

  const score = (matchName ? 0.5 : 0) + (matchGroup ? 0.5 : 0);

  const normalized = {
    json: {
      nome,
      primeiro_nome: primeiroNome,
      contato_tag: mentionTag,
      at_nome: atNomeRaw ? `@${atNomeRaw}` : '',
      at_numero: phone ? `@${phone}` : '',
      phone,
      categoria,
      telefone_csv: telefoneCsv,
      whatsapp_csv: whatsappCsv,
      origem_arquivo: origemArquivo,
      grupos_origem: groups,
      grupo_principal: groupMain,
      origem_responsavel: owner,
      ticket_interesse_raw: ticketRaw,
      ticket_interesse_valor: ticketValue,
      ticket_segmento: ticketSegment,
      perfil_grupo: profile,
      oportunidade_recomendada: opportunity,
      mensagem_contexto_origem: origemMensagem,
      eh_contato_salvo: String(row.eh_contato_salvo ?? ''),
      eh_negocio: String(row.eh_negocio ?? ''),
      eh_admin: String(row.eh_admin ?? ''),
      contato_id: `${phone}-${origemArquivo || 'local'}`,

      lead_nome_planilha: nome,
      lead_contato_planilha: phone,
      lead_grupo_planilha: groupMain,
      lead_responsavel_planilha: owner,
      agente_validacao: {
        modo: validationMode,
        alvo_nome: targetNameRaw || null,
        alvo_grupo: targetGroupRaw || null,
        match_nome: matchName,
        match_grupo: matchGroup,
        score,
      },
      agente_validacao_status: (matchName && matchGroup) ? 'aprovado' : 'aprovado_sem_alvo',
    },
  };

  if (nome) {
    namedContacts.push(normalized);
  } else {
    unnamedContacts.push(normalized);
  }
}

let out = [...namedContacts, ...unnamedContacts];

if (directTargetEnabled) {
  out = out.sort((a, b) => (b.json.agente_validacao?.score || 0) - (a.json.agente_validacao?.score || 0));
}

out = out.slice(0, maxContacts);
out = out.map((entry, index) => ({
  ...entry,
  json: {
    ...entry.json,
    dispatch_sequence: index + 1,
  },
}));

if (!out.length) {
  let message = `Nenhum contato valido encontrado na planilha local para audiencia \"${audienceMode}\".`;

  if (directTargetEnabled) {
    message = 'Nenhum contato encontrado para o alvo de validacao (nome/grupo).';
  } else if (groupFilters.length) {
    message = 'Nenhum contato encontrado para o filtro de grupo informado.';
  }

  return [{
    json: {
      _campaignDone: true,
      message,
      alvo_nome: targetNameRaw || null,
      alvo_grupo: targetGroupRaw || null,
    },
  }];
}

return out;

return [{
  json: {
    status: 'fora_janela_envio',
    message: 'Execucao encerrada: fora da janela permitida (09:00-17:00).',
    now: new Date().toISOString()
  }
}];

const nomeCompletoRaw = String($json.nome || '').trim();
const primeiroNomeRaw = String($json.primeiro_nome || '').trim();
const primeiroNome = primeiroNomeRaw || (nomeCompletoRaw ? nomeCompletoRaw.split(' ')[0] : '');
const nome = primeiroNome && primeiroNome.toLowerCase() !== 'cliente' ? primeiroNome : '';
const categoria = String($json.categoria || 'Cliente').trim() || 'Cliente';
const foco = String($env.CAMPAIGN_TEMPLATE_FOCUS || 'imoveis de luxo').trim();
const campaignId = String($env.CAMPAIGN_ID || `campanha_${new Date().toISOString().slice(0, 10)}`);
const templateMode = String($env.CAMPAIGN_TEMPLATE_MODE || 'hogar').toLowerCase();
const useAtMention = String($env.CAMPAIGN_USE_AT_MENTION || 'false').toLowerCase() === 'true';
const greetingStrategyRaw = String($env.CAMPAIGN_GREETING_STRATEGY || 'rotativo').trim().toLowerCase();
const greetingStrategy = ['rotativo', 'formal', 'consultivo', 'direto'].includes(greetingStrategyRaw) ? greetingStrategyRaw : 'rotativo';
const delayProfileRaw = String($env.CAMPAIGN_DELAY_PROFILE || '').trim();
const delaySwitchEvery = Math.max(1, Number($env.CAMPAIGN_DELAY_SWITCH_EVERY || 8));

const normalizeTag = (value) => {
  const clean = String(value || '')
    .trim()
    .replace(/^@+/, '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^\p{L}\p{N}_.]/gu, '')
    .toLowerCase();
  return clean ? `@${clean}` : '';
};

const normalizeText = (value) => String(value || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase();

const originalPhone = String($json.phone || '').replace(/\D/g, '');
const forcePhoneRaw = String($env.CAMPAIGN_FORCE_PHONE || '').trim();
const forceDigits = forcePhoneRaw.replace(/\D/g, '');
const forcedPhone = forceDigits ? (forceDigits.startsWith('55') ? forceDigits : `55${forceDigits}`) : '';
const usarNumeroTeste = forcedPhone.length >= 12 && forcedPhone.length <= 13;
const phoneDestino = usarNumeroTeste ? forcedPhone : originalPhone;
const alertaNumeroTeste = forcePhoneRaw && !usarNumeroTeste
  ? 'CAMPAIGN_FORCE_PHONE invalido. Seguindo telefone original.'
  : '';

const telefonePlanilha = String($json.telefone_csv || originalPhone || '').replace(/\D/g, '');
const grupoOrigemBruto = String($json.grupo_principal || $json.grupos_origem || '').trim();
const grupoOrigem = grupoOrigemBruto
  .replace(/excel results/ig, '')
  .replace(/\s*\|\s*/g, ' | ')
  .replace(/\s+/g, ' ')
  .trim();
const grupoPrincipal = grupoOrigem ? grupoOrigem.split('|')[0].trim() : '';

const mentionFromHandle = normalizeTag(
  $json.contato_tag
    || $json.arroba
    || $json.handle
    || $json.username
    || $json.user
    || $json.instagram
    || ''
);
const mentionFromName = normalizeTag($json.at_nome || nome);
const mentionFromPhone = normalizeTag($json.at_numero || originalPhone || phoneDestino);
const mentionTag = mentionFromHandle || mentionFromName || mentionFromPhone || '@cliente';
const mentionText = useAtMention ? mentionTag : '';
const fallbackSaudacao = mentionText || (phoneDestino ? `+${phoneDestino}` : 'cliente');
const saudacaoAlvo = nome ? (mentionText ? `${nome} (${mentionText})` : nome) : fallbackSaudacao;
const tzSaudacao = String($env.CAMPAIGN_TIMEZONE || 'America/Sao_Paulo');
const horaSaudacao = Number(new Intl.DateTimeFormat('en-US', { hour: '2-digit', hour12: false, timeZone: tzSaudacao }).format(new Date()));
const saudacaoPeriodo = horaSaudacao < 12 ? 'Bom dia' : (horaSaudacao < 18 ? 'Boa tarde' : 'Boa noite');

const parseDelayProfiles = (raw, fallbackMin, fallbackMax) => {
  const defaults = [{ min: fallbackMin, max: fallbackMax }];
  if (!raw) return defaults;

  const parsed = String(raw)
    .split(/[|;]/)
    .map((chunk) => chunk.trim())
    .filter(Boolean)
    .map((chunk) => {
      const match = chunk.match(/^(\d+)(?:\s*[-:]\s*(\d+))?$/);
      if (!match) return null;
      const a = Number(match[1]);
      const b = Number(match[2] || match[1]);
      if (!Number.isFinite(a) || !Number.isFinite(b)) return null;
      const min = Math.max(1, Math.min(a, b));
      const max = Math.max(min, Math.max(a, b));
      return { min, max };
    })
    .filter(Boolean);

  return parsed.length ? parsed : defaults;
};

const fallbackDelayMin = Math.max(1, Number($env.CAMPAIGN_DELAY_MIN_SECONDS || 25));
const fallbackDelayMax = Math.max(fallbackDelayMin, Number($env.CAMPAIGN_DELAY_MAX_SECONDS || 45));
const delayProfiles = parseDelayProfiles(delayProfileRaw, fallbackDelayMin, fallbackDelayMax);
const dispatchSequence = Math.max(1, Number($json.dispatch_sequence || 1));
const delayProfileIndex = Math.floor((dispatchSequence - 1) / delaySwitchEvery) % delayProfiles.length;
const selectedDelayProfile = delayProfiles[delayProfileIndex] || { min: fallbackDelayMin, max: fallbackDelayMax };
const delaySeconds = Math.floor(selectedDelayProfile.min + Math.random() * (selectedDelayProfile.max - selectedDelayProfile.min + 1));

const origemResponsavel = String($json.origem_responsavel || 'Equipe Hogar').trim();
const perfilGrupo = String($json.perfil_grupo || 'geral').trim().toLowerCase();
const ticketSegmento = String($json.ticket_segmento || 'premium').trim().toLowerCase();
const ticketRaw = String($json.ticket_interesse_raw || '').trim();
const oportunidade = String($json.oportunidade_recomendada || foco).trim();
const contextoOrigem = String($json.mensagem_contexto_origem || '').trim() ||
  (grupoPrincipal
    ? `Peguei seu contato no grupo "${grupoPrincipal}" com ${origemResponsavel}.`
    : `Peguei seu contato por indicacao com ${origemResponsavel}.`);

const hashSeed = `${originalPhone}|${campaignId}|${grupoPrincipal}|${categoria}|${nome}|${mentionTag}|${perfilGrupo}|${ticketSegmento}`;
let hash = 0;
for (const ch of hashSeed) {
  hash = ((hash << 5) - hash + ch.charCodeAt(0)) >>> 0;
}

const pick = (arr, salt = 0) => {
  if (!arr.length) return '';
  const index = (hash + salt + Math.floor(Math.random() * 997)) % arr.length;
  return arr[index];
};

const maybe = (value, chance = 0.5) => (Math.random() < chance ? value : '');

const abordagemPorPerfil = {
  parceiro: 'Temos uma oportunidade alinhada para parceria comercial da sua rede.',
  investidor: 'Temos uma oportunidade com foco em valorizacao e estrutura de investimento.',
  morador: 'Temos uma oportunidade residencial que pode fazer sentido para voce.',
  luxo: 'Temos uma oportunidade premium da carteira Hogar Imoveis de Luxo.',
  geral: 'Temos uma oportunidade imobiliaria selecionada para seu perfil.',
};

const ctaPorPerfil = {
  parceiro: [
    'Posso te enviar os detalhes de parceria e comissionamento?',
    'Quer que eu te mande agora as condicoes comerciais dessa oportunidade?',
  ],
  investidor: [
    'Posso te enviar o resumo de ticket, potencial e condicoes dessa oportunidade?',
    'Quer que eu te mande uma analise objetiva dessa opcao?',
  ],
  morador: [
    'Posso te encaminhar os detalhes e disponibilidade por aqui?',
    'Quer que eu te envie um resumo com condicoes e proximos passos?',
  ],
  luxo: [
    'Posso te enviar agora os detalhes completos dessa oportunidade premium?',
    'Quer que eu te encaminhe a apresentacao dessa opcao de alto padrao?',
  ],
  geral: [
    'Posso te enviar os detalhes dessa oportunidade agora?',
    'Quer que eu te encaminhe um resumo rapido por aqui?',
  ],
};

let mensagemFinal = '';
let templateName = `T${(hash % 7) + 1}`;

if (templateMode === 'debug') {
  templateName = 'DEBUG';
  mensagemFinal = [
    'TESTE TECNICO - AGENTE VALIDACAO',
    `contato_id: ${$json.contato_id || '-'}`,
    `nome: ${nome || '-'}`,
    `mention_tag: ${mentionText || '(desabilitado)'}`,
    `grupo_principal: ${grupoPrincipal || '-'}`,
    `origem_responsavel: ${origemResponsavel}`,
    `perfil_grupo: ${perfilGrupo}`,
    `ticket_segmento: ${ticketSegmento}`,
    `ticket_raw: ${ticketRaw || '-'}`,
    `oportunidade: ${oportunidade}`,
    `contexto_origem: ${contextoOrigem}`,
    `telefone_planilha: +${telefonePlanilha || '-'}`,
    `telefone_destino: +${phoneDestino || '-'}`,
    `campaign_id: ${campaignId}`,
  ].join('\n');
}

if (templateMode === 'hogar') {
  const buildOpenings = (targetLabel) => {
    const poolFormal = [
      `${saudacaoPeriodo}, ${targetLabel}. Aqui e da equipe Hogar Imoveis de Luxo.`,
      `${saudacaoPeriodo}, ${targetLabel}. Tudo bem? Falando da Hogar Imoveis de Luxo.`,
      `${saudacaoPeriodo}, ${targetLabel}. Time comercial da Hogar Imoveis de Luxo por aqui.`,
    ];

    const poolConsultivo = [
      `${saudacaoPeriodo}, ${targetLabel}. Posso te mandar uma oportunidade alinhada ao seu perfil?`,
      `${saudacaoPeriodo}, ${targetLabel}. Tudo certo por ai? Separei um contato consultivo rapido.`,
      `${saudacaoPeriodo}, ${targetLabel}. Quero te apresentar uma oportunidade com abordagem consultiva.`,
    ];

    const poolDireto = [
      `${saudacaoPeriodo}, ${targetLabel}. Tenho uma oportunidade objetiva para te apresentar.`,
      `${saudacaoPeriodo}, ${targetLabel}. Vim direto ao ponto com uma oportunidade selecionada.`,
      `${saudacaoPeriodo}, ${targetLabel}. Separei uma opcao que pode fazer sentido para voce.`,
    ];

    if (greetingStrategy === 'formal') return poolFormal;
    if (greetingStrategy === 'consultivo') return poolConsultivo;
    if (greetingStrategy === 'direto') return poolDireto;
    return [...poolFormal, ...poolConsultivo, ...poolDireto];
  };

  const aberturasComNome = buildOpenings(saudacaoAlvo);
  const aberturasSemNome = buildOpenings(fallbackSaudacao);

  const contextos = [
    `${contextoOrigem} Vim te enviar uma oportunidade de ${oportunidade}.`,
    `${contextoOrigem} Separei para voce uma oportunidade de ${oportunidade}.`,
    `${contextoOrigem} Tenho uma oportunidade de ${oportunidade} que pode fazer sentido para voce.`,
  ];

  if (grupoPrincipal) {
    contextos.push(`No grupo "${grupoPrincipal}", identifiquei um perfil alinhado para ${oportunidade}.`);
  }

  if (ticketRaw) {
    contextos.push(`Pelo seu perfil de ticket (${ticketRaw}), separei uma opcao bem direcionada.`);
  }

  const provas = [
    abordagemPorPerfil[perfilGrupo] || abordagemPorPerfil.geral,
    'Atendimento consultivo, sem pressao comercial.',
    'Se nao fizer sentido agora, sem problema algum.',
  ];

  const ctas = ctaPorPerfil[perfilGrupo] || ctaPorPerfil.geral;

  const assinaturas = [
    'Equipe Hogar Imoveis de Luxo',
    'Consultoria Hogar Imoveis de Luxo',
    'Time Comercial Hogar Imoveis de Luxo',
  ];

  const abertura = nome ? pick(aberturasComNome, 11) : pick(aberturasSemNome, 13);
  const contexto = pick(contextos, 17);
  const prova = pick(provas, 19);
  const cta = pick(ctas, 23);
  const assinatura = pick(assinaturas, 31);
  const fechamento = maybe('Aguardo seu retorno.', 0.72);

  mensagemFinal = [abertura, contexto, prova, cta, fechamento, `(${assinatura})`]
    .filter(Boolean)
    .join(' ');

  templateName = `HOGAR_${perfilGrupo.toUpperCase()}_${ticketSegmento.toUpperCase()}_V${((hash + Math.floor(Math.random() * 1000)) % 25) + 1}`;
}

if (templateMode !== 'hogar' && templateMode !== 'debug') {
  const basicos = [
    `${saudacaoAlvo}, ${contextoOrigem} Vim te apresentar uma oportunidade de ${oportunidade}. Aguardo seu retorno!`,
    `${saudacaoAlvo}, tudo certo? Somos da Hogar Imoveis de Luxo. ${contextoOrigem} Posso te enviar uma oportunidade de ${oportunidade}?`,
    `${saudacaoAlvo}, aqui e da Hogar Imoveis de Luxo. ${contextoOrigem} Tenho uma oportunidade de ${oportunidade} para te mostrar.`,
  ];

  mensagemFinal = pick(basicos, 41);
}

return [{
  json: {
    ...$json,
    campaignId,
    template_id: templateName,
    mensagem_final: mensagemFinal,
    categoria,
    mention_tag: mentionTag,
    origem_responsavel: origemResponsavel,
    perfil_grupo: perfilGrupo,
    ticket_segmento: ticketSegmento,
    oportunidade_grupo: oportunidade,
    at_nome: mentionFromName,
    at_numero: mentionFromPhone,
    phone_original: originalPhone,
    phone_destino: phoneDestino,
    phone: phoneDestino,
    modo_teste_numero: usarNumeroTeste,
    alerta_numero_teste: alertaNumeroTeste,
    template_mode: templateMode,
    delay_seconds: delaySeconds,
    delay_profile_index: delayProfileIndex,
    delay_profile_range: `${selectedDelayProfile.min}-${selectedDelayProfile.max}`,
    dispatch_sequence: dispatchSequence,
  },
}];

return [{
  json: {
    ...$json,
    envio_ok: true,
    envio_status: 'dry_run',
    envio_em: new Date().toISOString(),
    provider_message_id: '',
    provider_status: 'DRY_RUN',
    erro_envio: ''
  }
}];

const leadData = $('Montar Template Teste').item.json;
const responseData = $input.item.json || {};
const inputError = $input.item.error || null;

const providerMessageId = responseData?.key?.id || '';
const providerStatus = responseData.status || (providerMessageId ? 'PENDING' : 'ERROR');

const providerErrorMessage =
  (inputError && inputError.message)
  || responseData.message
  || responseData.error
  || '';

const hasProviderError = !!providerErrorMessage && !providerMessageId;
const envioOk = !!providerMessageId && !hasProviderError;

return [{
  json: {
    ...leadData,
    envio_ok: envioOk,
    envio_status: envioOk ? 'enviado' : 'erro',
    envio_em: new Date().toISOString(),
    provider_message_id: providerMessageId,
    provider_status: providerStatus,
    erro_envio: envioOk ? '' : (providerErrorMessage || 'Erro desconhecido no envio Evolution')
  }
}];
